```plantuml
@startuml
hide circle
skinparam classAttributeIconSize 0

class Maker {
  actor
}

class Puzzle {
  grid dimension
  complexity
}

class Solver {
  actor
}

class RowsColumns {
  priorities
  constraints
}

class Solutions {
  general
  row/column
}

class Pixels {
  black
  white
}

Maker "1" - "*" Puzzle : design >
Puzzle "*" - "1" Solver : < solve

Puzzle "1" *-- "*" RowsColumns : contains >
Puzzle "1" -- "1" Solutions

RowsColumns "*" - "*" Solutions

RowsColumns "1" *-- "*" Pixels : contains >

@enduml
```
